{{familytree|border=0|||)|-|-|-|-|.|}}
{{familytree|border=0|01|||||02| 01=(9) [[開化天皇]]|02=[[大彦命]]<br />（北陸）}}
{{familytree|border=0|||)|-|-|.||!|}}
{{familytree|border=0|01||02|03| 01=(10) [[崇神天皇]]|02=[[彦坐王]]|03=[[武渟川別]]<br />（東海）}}
{{familytree|border=0|||!|||!|}}
{{familytree|border=0|||!||01| 01='''丹波道主命'''<br />（丹波）}}
{{familytree|border=0|||!|||!}}
{{familytree|border=0|01|y|02| 01=(11) [[垂仁天皇]]|02=[[日葉酢媛命|{{color|#FC4E6B|日葉酢媛命}}]]}}
{{familytree|border=0||||!|}}
{{familytree|border=0|||01| 01=(12) [[景行天皇]]}}
{{familytree/end}}
